export function generateStaking(config) {
  const stakingToken = config.stakingToken || '0x0000000000000000000000000000000000000000';
  const rewardToken = config.rewardToken || '0x0000000000000000000000000000000000000000';
  const rewardRate = config.rewardRate || '100';
  const lockPeriod = config.lockPeriod || '86400';
  const contractName = config.contractName || 'MonadStaking';

  return `// SPDX-License-Identifier: MIT
// Generated by Monad Build.exe — NX Terminal
// Target: Monad Testnet (Chain ID 10143)
// Compiler: solc ^0.8.28, evmVersion: "prague"
//
// MONAD OPTIMIZATION NOTES:
// - Monad charges gas based on gas LIMIT, not gas used. Set tight limits.
// - Cold SLOAD costs 8,100 gas (vs 2,100 on Ethereum). Cache storage reads.
// - Cold account access costs 10,100 gas. Minimize cross-contract cold calls.

pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract ${contractName} is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public immutable stakingToken;
    IERC20 public immutable rewardToken;

    uint256 public rewardRate = ${rewardRate}; // rewards per second
    uint256 public lockPeriod = ${lockPeriod}; // lock duration in seconds
    uint256 public lastUpdateTime;
    uint256 public rewardPerTokenStored;

    mapping(address => uint256) public userRewardPerTokenPaid;
    mapping(address => uint256) public rewards;
    mapping(address => uint256) public balances;
    mapping(address => uint256) public stakeTimestamp;

    uint256 public totalStaked;

    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardClaimed(address indexed user, uint256 reward);

    constructor(address initialOwner) Ownable(initialOwner) {
        stakingToken = IERC20(${stakingToken});
        rewardToken = IERC20(${rewardToken});
        lastUpdateTime = block.timestamp;
    }

    modifier updateReward(address account) {
        // Cache storage reads for Monad gas optimization
        uint256 _rewardPerTokenStored = rewardPerToken();
        rewardPerTokenStored = _rewardPerTokenStored;
        lastUpdateTime = block.timestamp;

        if (account != address(0)) {
            rewards[account] = earned(account);
            userRewardPerTokenPaid[account] = _rewardPerTokenStored;
        }
        _;
    }

    function rewardPerToken() public view returns (uint256) {
        uint256 _totalStaked = totalStaked; // Cache cold SLOAD
        if (_totalStaked == 0) return rewardPerTokenStored;
        return rewardPerTokenStored + (
            (block.timestamp - lastUpdateTime) * rewardRate * 1e18 / _totalStaked
        );
    }

    function earned(address account) public view returns (uint256) {
        return (
            balances[account] * (rewardPerToken() - userRewardPerTokenPaid[account]) / 1e18
        ) + rewards[account];
    }

    function stake(uint256 amount) external nonReentrant updateReward(msg.sender) {
        require(amount > 0, "Cannot stake 0");
        totalStaked += amount;
        balances[msg.sender] += amount;
        stakeTimestamp[msg.sender] = block.timestamp;
        stakingToken.safeTransferFrom(msg.sender, address(this), amount);
        emit Staked(msg.sender, amount);
    }

    function withdraw(uint256 amount) external nonReentrant updateReward(msg.sender) {
        require(amount > 0, "Cannot withdraw 0");
        require(balances[msg.sender] >= amount, "Insufficient balance");
        require(
            block.timestamp >= stakeTimestamp[msg.sender] + lockPeriod,
            "Still locked"
        );
        totalStaked -= amount;
        balances[msg.sender] -= amount;
        stakingToken.safeTransfer(msg.sender, amount);
        emit Withdrawn(msg.sender, amount);
    }

    function claimReward() external nonReentrant updateReward(msg.sender) {
        uint256 reward = rewards[msg.sender];
        if (reward > 0) {
            rewards[msg.sender] = 0;
            rewardToken.safeTransfer(msg.sender, reward);
            emit RewardClaimed(msg.sender, reward);
        }
    }

    function setRewardRate(uint256 _rewardRate) external onlyOwner updateReward(address(0)) {
        rewardRate = _rewardRate;
    }
}
`;
}
